// Curated quote library for the "Cytat na dziś" panel. Bundled (offline, free,
// reliable attribution). Each quote is in its ORIGINAL language with a Polish
// translation (null when the original is already Polish), an author and a
// domain. Client-safe (pure data — no server deps), so both the panel and the
// server actions can import it. Extend freely; ids must stay stable (favourites
// reference them).

export type QuoteLang = "pl" | "en" | "la" | "fr" | "de" | "es" | "it";

export type Quote = {
  id: string;
  lang: QuoteLang;
  text: string; // original language
  author: string;
  translation: string | null; // Polish; null when original is Polish
  category: string; // domain, PL label
};

export const LANG_LABELS: Record<QuoteLang, string> = {
  pl: "polski",
  en: "angielski",
  la: "łacina",
  fr: "francuski",
  de: "niemiecki",
  es: "hiszpański",
  it: "włoski",
};

