export const QUOTE_BY_ID: Record<string, Quote> = Object.fromEntries(
  QUOTES.map((q) => [q.id, q])
);

// Stable per-day pick: same quote for a given date. Simple string hash so the
// choice is deterministic without storing anything.
export function dailyQuoteId(dayKey: string): string {
  let hash = 0;
  for (let i = 0; i < dayKey.length; i++) {
    hash = (hash * 31 + dayKey.charCodeAt(i)) | 0;
  }
  const index = Math.abs(hash) % QUOTES.length;
  return QUOTES[index].id;
}

/** A random quote id, optionally different from `excludeId`. */
export function randomQuoteId(excludeId?: string): string {
  if (QUOTES.length <= 1) return QUOTES[0].id;
  let q = QUOTES[Math.floor(Math.random() * QUOTES.length)];
  while (q.id === excludeId) q = QUOTES[Math.floor(Math.random() * QUOTES.length)];
  return q.id;
}

export function isKnownQuoteId(id: string): boolean {
  return id in QUOTE_BY_ID;
}
